<template>
  <div class="flex h-screen w-screen flex-col justify-center items-center">
    <transition name="slide-top-fade">
      <div v-if="show" class="select-none">
        <h1
          class="text-4xl text-center sm:text-6xl font-bold text-gray-600 block"
        >
          {{ $t("nav.name") }}
        </h1>
        <p
          :class="
            $i18n.locale == 'en'
              ? 'text-center sm:text-left'
              : 'text-center sm:text-right'
          "
        >
          {{ $t("nav.resume") }}
        </p>
        <div class="text-center">
          <span
            @click="$i18n.locale = 'en'"
            :class="
              $i18n.locale == 'en'
                ? 'font-Quick inline-block cursor-pointer rounded-md m-2 p-2 font-bold bg-black bg-opacity-10'
                : 'font-Quick inline-block cursor-pointer rounded-md m-2 p-2 hover:bg-black hover:bg-opacity-10'
            "
            >English</span
          >
          <span
            @click="$i18n.locale = 'fa'"
            :class="
              $i18n.locale == 'fa'
                ? 'font-Cairo inline-block cursor-pointer rounded-md m-2 p-2 font-bold bg-black bg-opacity-10'
                : 'font-Cairo inline-block cursor-pointer rounded-md m-2 p-2 hover:bg-black hover:bg-opacity-10'
            "
            >فارسی</span
          >
        </div>
      </div>
    </transition>
  </div>
</template>
<script>
import ToBottom from "@/components/transitions/ToBottom.vue";

const sleep = (time) =>
  new Promise((res) => setTimeout(res, time, "done sleeping"));

export default {
  components: {
    ToBottom,
  },
  data() {
    return {
      show: false,
    };
  },
  mounted() {
    this.show = true;
  },
  methods: {
    onWheel(e) {
      if (e.deltaY > 0) this.replaceRoute();
    },
    replaceRoute() {
      this.$router.push("/@/about");
      sleep(500);
    },
  },
};
</script>
<style lang="scss" scoped>
.slide-top-fade-enter-active {
  transition: all 1s ease-out;
}

.slide-top-fade-leave-active {
  transition: all 1.8s cubic-bezier(1, 0.5, 0.8, 1);
}

.slide-top-fade-enter-from,
.slide-top-fade-leave-to {
  transform: translateY(40px);
  opacity: 0;
}
</style>
